sourceQuestion:
What is the output printed by the following program?

#include <stdio.h>
int f(int n, int k) {
    if (n == 0) return 0;
    else if (n % 2) return f(n/2, 2*k) + k;
    else return f(n/2, 2*k) - k;
}
int main() {
    printf("%d", f(20, 1));
    return 0;
}

A. 5
B. 8
C. 9
D. 20

